        ax3.set_xlabel(r"$z_t$")
        ax3.set_ylabel("P(Z \u2264 z) [log scale]")
        ax3.legend(loc="upper left", fontsize=8, framealpha=0.8)

        # --- Panel 4: CDF Comparison ---
